mapper.select:
select count(*)
from subscribers

  deleted_at is null

    and lower(email) like #{keyword}


    and status = #{status}

select id, email, unsubscribe_token, active, status, confirmation_token, confirmed_at,
  unsubscribed_at, bounced_at, failure_count, last_delivery_status, last_delivery_error,
  last_delivery_at, created_at, updated_at
from subscribers

  deleted_at is null

    and lower(email) like #{keyword}


    and status = #{status}


order by created_at desc, id desc
limit #{limit} offset #{offset}

select id, email, unsubscribe_token, status
from subscribers
where deleted_at is null and status = 'ACTIVE' and id > #{afterId}
order by id asc
limit #{limit}
